
const MONTHS=['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];
const WK_S=['SEG','TER','QUA','QUI','SEX','SÁB','DOM'];
const WK_L=['Segunda','Terça','Quarta','Quinta','Sexta','Sábado','Domingo'];
const TCOLORS={green:'#00E896',gold:'#F5C347',coral:'#FF6B6B',sky:'#38BDF8'};
const COLORS=['#00E896','#F5C347','#FF6B6B','#38BDF8','#8B5CF6','#F43F5E','#F97316','#06B6D4'];

function jsDow2mon(d){return(d+6)%7}
function getMonStart(d){
  const s=new Date(d);
  const dw=s.getDay();
  const diff=dw===0?-6:1-dw;
  s.setDate(s.getDate()+diff);
  s.setHours(0,0,0,0);
  return s;
}
function dkey(y,m,d){return`${y}-${m}-${d}`}

let view='monthly';
let today=new Date();
let cursor=new Date(today.getFullYear(),today.getMonth(),1);
let wkcursor=getMonStart(today);
let evs=JSON.parse(localStorage.getItem('iea_ev')||'{}');
let anns=JSON.parse(localStorage.getItem('iea_ann')||'[]');
let mdate=null,eidx=null,scolor=COLORS[0];
let shareDataURL=null;

function saveEv(){localStorage.setItem('iea_ev',JSON.stringify(evs))}
function saveAnn(){localStorage.setItem('iea_ann',JSON.stringify(anns))}

/* RENDER */
function render(){
  if(view==='monthly')rMonth();
  else if(view==='weekly')rWeek();
  else rAnn();
}

function rMonth(){
  const y=cursor.getFullYear(),m=cursor.getMonth();
  document.getElementById('ntitle').textContent=`${MONTHS[m]} ${y}`;
  document.getElementById('hdr-year').textContent=y;
  document.getElementById('mbig').textContent=MONTHS[m];
  const firstJs=new Date(y,m,1).getDay();
  const firstMon=firstJs===0?6:firstJs-1;
  const dim=new Date(y,m+1,0).getDate();
  document.getElementById('wkrow').innerHTML=
    WK_S.map((d,i)=>`<div class="wkd${i>=5?' we':''}">${d}</div>`).join('');
  const grid=document.getElementById('dgrid');
  grid.innerHTML='';
  for(let i=0;i<firstMon;i++){
    const e=document.createElement('div');e.className='dc empty';grid.appendChild(e);
  }
  for(let d=1;d<=dim;d++){
    const dt=new Date(y,m,d);
    const monD=jsDow2mon(dt.getDay());
    const isT=(d===today.getDate()&&m===today.getMonth()&&y===today.getFullYear());
    const k=dkey(y,m+1,d);
    const de=evs[k]||[];
    const isWe=monD>=5;
    const cell=document.createElement('div');
    cell.className=`dc${isWe?' wd':''}`;
    cell.onclick=()=>openModal(y,m+1,d);
    const fe=de[0];
    let nCls='dnum';
    let nSt='';
    if(isT) nCls+=' tod';
    else if(fe) nSt=`style="background:${fe.color}35;color:${fe.color}"`;
    let h=`<div class="${nCls}" ${nSt}>${d}</div>`;
    de.forEach((ev,i)=>{
      const lb=ev.time?`${ev.name} ${ev.time}`:ev.name;
      h+=`<span class="chip" style="background:${ev.color}25;color:${ev.color}" onclick="editEv(event,'${k}',${i})">${lb}</span>`;
    });
    cell.innerHTML=h;
    grid.appendChild(cell);
  }
}

function rWeek(){
  const ws=new Date(wkcursor);
  const we=new Date(ws);we.setDate(we.getDate()+6);
  const fmt=d=>`${d.getDate()} ${MONTHS[d.getMonth()].substring(0,3)}`;
  document.getElementById('ntitle').textContent=`${fmt(ws)} – ${fmt(we)}`;
  const cont=document.getElementById('wrows');
  cont.innerHTML='';
  for(let i=0;i<7;i++){
    const dt=new Date(ws);dt.setDate(ws.getDate()+i);
    const monD=jsDow2mon(dt.getDay());
    const isT=dt.toDateString()===today.toDateString();
    const k=dkey(dt.getFullYear(),dt.getMonth()+1,dt.getDate());
    const de=evs[k]||[];
    const row=document.createElement('div');row.className='wrow';
    let eh='';
    de.forEach((ev,idx)=>{
      const lb=ev.time?`${ev.name} · ${ev.time}`:ev.name;
      eh+=`<div class="ps" style="background:${ev.color}20;border:1px solid ${ev.color}45;color:${ev.color}" onclick="editEv(event,'${k}',${idx})">
        <span style="width:5px;height:5px;border-radius:50%;background:${ev.color};flex-shrink:0;display:inline-block"></span>${lb}</div>`;
    });
    eh+=`<button class="padd" onclick="openModal(${dt.getFullYear()},${dt.getMonth()+1},${dt.getDate()})">+ Evento</button>`;
    /* FIX: día number sempre mesmo tamanho com String.padStart */
    const dayStr=String(dt.getDate()).padStart(2,'0');
    row.innerHTML=`
      <div class="wlbl">
        <div class="wdn">${WK_L[monD]}</div>
        <div class="wdnum${isT?' tod':''}">${dayStr}</div>
      </div>
      <div class="wevs">${eh}</div>`;
    cont.appendChild(row);
  }
}

function rAnn(){
  document.getElementById('ntitle').textContent='Avisos';
  const list=document.getElementById('alist');
  if(!anns.length){list.innerHTML='<div class="empt">📋 Nenhum aviso ainda.</div>';return}
  list.innerHTML=anns.map((a,i)=>{
    const c=TCOLORS[a.type]||'#00E896';
    return`<div class="acard">
      <div class="actit"><span class="atdot" style="background:${c}"></span>${a.title}</div>
      <div class="actxt">${a.text}</div>
      <div class="acbot">
        <span class="acdate">${a.date}</span>
        <div class="acacts">
          <button class="bsh" onclick="openShareAnn(${i})">📤 Compartilhar</button>
          <button class="bdel" onclick="delAnn(${i})">Excluir</button>
        </div>
      </div></div>`;
  }).join('');
}

/* NAV */
function prev(){
  if(view==='monthly'){cursor.setMonth(cursor.getMonth()-1);rMonth();}
  else if(view==='weekly'){wkcursor.setDate(wkcursor.getDate()-7);rWeek();}
}
function next(){
  if(view==='monthly'){cursor.setMonth(cursor.getMonth()+1);rMonth();}
  else if(view==='weekly'){wkcursor.setDate(wkcursor.getDate()+7);rWeek();}
}

/* TABS */
function sw(v){
  view=v;
  document.querySelectorAll('.tab').forEach((t,i)=>t.classList.toggle('on',['monthly','weekly','announce'][i]===v));
  document.getElementById('mv').style.display=v==='monthly'?'':'none';
  document.getElementById('wv').style.display=v==='weekly'?'':'none';
  document.getElementById('av').style.display=v==='announce'?'':'none';
  document.getElementById('nav-row').style.display=v==='announce'?'none':'';
  if(v==='weekly') wkcursor=getMonStart(new Date(cursor.getFullYear(),cursor.getMonth(),1));
  if(v==='announce'){document.getElementById('ntitle').textContent='Avisos';rAnn();}
  else render();
}

/* EVENT MODAL */
function buildC(sel){
  document.getElementById('crow').innerHTML=COLORS.map(c=>
    `<div class="cc${c===sel?' sel':''}" style="background:${c}" onclick="pc('${c}')"></div>`
  ).join('');
}
function openModal(y,m,d){
  mdate={y,m,d};eidx=null;scolor=COLORS[0];
  document.getElementById('mtit').textContent=`Evento – ${String(d).padStart(2,'0')}/${String(m).padStart(2,'0')}`;
  document.getElementById('evname').value='';
  document.getElementById('evtime').value='';
  buildC(scolor);
  document.getElementById('macts').innerHTML=
    `<button class="mc" onclick="closeMod()">Cancelar</button>
     <button class="ms" onclick="saveEv2()">Salvar</button>`;
  document.getElementById('moverlay').classList.add('open');
  setTimeout(()=>document.getElementById('evname').focus(),200);
}
function editEv(e,k,idx){
  e.stopPropagation();
  const ev=evs[k][idx];
  const p=k.split('-');
  mdate={y:+p[0],m:+p[1],d:+p[2]};eidx={k,idx};scolor=ev.color;
  document.getElementById('mtit').textContent='Editar Evento';
  document.getElementById('evname').value=ev.name;
  document.getElementById('evtime').value=ev.time||'';
  buildC(scolor);
  document.getElementById('macts').innerHTML=
    `<button class="md" onclick="delEv()">Excluir</button>
     <button class="mc" onclick="closeMod()">Cancelar</button>
     <button class="ms" onclick="saveEv2()">Salvar</button>`;
  document.getElementById('moverlay').classList.add('open');
}
function pc(c){scolor=c;buildC(c);}
function closeMod(){document.getElementById('moverlay').classList.remove('open');}
function saveEv2(){
  const n=document.getElementById('evname').value.trim();
  if(!n){document.getElementById('evname').focus();return;}
  const t=document.getElementById('evtime').value.trim();
  const ev={name:n,time:t,color:scolor};
  if(eidx){evs[eidx.k][eidx.idx]=ev;}
  else{const k=dkey(mdate.y,mdate.m,mdate.d);if(!evs[k])evs[k]=[];evs[k].push(ev);}
  saveEv();closeMod();render();
}
function delEv(){
  if(!eidx)return;
  evs[eidx.k].splice(eidx.idx,1);
  if(!evs[eidx.k].length)delete evs[eidx.k];
  saveEv();closeMod();render();
}

/* ANNOUNCE */
function crAnn(){
  const t=document.getElementById('atit').value.trim();
  const x=document.getElementById('atxt').value.trim();
  if(!t||!x)return;
  const tp=document.getElementById('atype').value;
  const now=new Date();
  const dt=`${String(now.getDate()).padStart(2,'0')}/${String(now.getMonth()+1).padStart(2,'0')}/${now.getFullYear()}`;
  anns.unshift({title:t,text:x,type:tp,date:dt});
  saveAnn();
  document.getElementById('atit').value='';
  document.getElementById('atxt').value='';
  rAnn();
}
function delAnn(i){anns.splice(i,1);saveAnn();rAnn();}

/* SHARE */
function scTop(tagText){
  return`
  <div class="sc-ring"></div><div class="sc-ring2"></div>
  <div class="sc-top">
    <div class="sc-logo-wrap">
      <div class="sc-logo"><img src="data:image/png;base64," alt=""></div>
      <div>
        <div class="sc-church">Ieadern</div>
        <div class="sc-church-sub">Parque Verde</div>
      </div>
    </div>
    <div class="sc-top-tag">${tagText}</div>
  </div>`;
}
function scFooter(sub){
  return`<div class="sc-footer">
    <div class="sc-footer-name">Ieadern Parque Verde${sub?` · ${sub}`:''}</div>
    <div class="sc-footer-badge">Igreja</div>
  </div>`;
}

function openShareMonth(){
  const y=cursor.getFullYear(),m=cursor.getMonth();
  const dim=new Date(y,m+1,0).getDate();
  const specials=[];
  for(let d=1;d<=dim;d++){
    const k=dkey(y,m+1,d);
    if(evs[k]&&evs[k].length){
      const dt=new Date(y,m,d);
      const monD=jsDow2mon(dt.getDay());
      evs[k].forEach(ev=>specials.push({d,wk:WK_L[monD],ev}));
    }
  }
  const evHtml=specials.length
    ?specials.map(s=>`
      <div class="sc-ev" style="border-left-color:${s.ev.color}">
        <div class="sc-ev-left">
          <div class="sc-ev-day">${String(s.d).padStart(2,'0')}</div>
          <div class="sc-ev-wk">${s.wk.substring(0,3).toUpperCase()}</div>
        </div>
        <div class="sc-ev-divider"></div>
        <div class="sc-ev-info">
          <div class="sc-ev-name">${s.ev.name}</div>
          ${s.ev.time?`<div class="sc-ev-time">⏰ ${s.ev.time}</div>`:''}
        </div>
      </div>`).join('')
    :`<div class="sc-noev">Nenhum evento especial este mês</div>`;
  buildSC(`<div class="sc"><div class="sc-bg"></div><div class="sc-inner">
    ${scTop(MONTHS[m])}
    <div class="sc-month">${MONTHS[m]}</div>
    <div class="sc-month-sub">${y} · Programação</div>
    <div class="sc-ev-list">${evHtml}</div>
    ${scFooter()}
  </div></div>`);
  openShareModal();
}

function openShareWeek(){
  const ws=new Date(wkcursor);
  const fmt=d=>`${d.getDate()} ${MONTHS[d.getMonth()].substring(0,3)}`;
  const we=new Date(ws);we.setDate(we.getDate()+6);
  const rows=[];
  for(let i=0;i<7;i++){
    const dt=new Date(ws);dt.setDate(ws.getDate()+i);
    const monD=jsDow2mon(dt.getDay());
    const k=dkey(dt.getFullYear(),dt.getMonth()+1,dt.getDate());
    const de=evs[k]||[];
    if(de.length) rows.push({d:dt.getDate(),wk:WK_L[monD],items:de});
  }
  const rowsHtml=rows.length
    ?rows.map(r=>`
      <div class="sc-wk-row">
        <div class="sc-wk-date">
          <div class="sc-wk-num">${String(r.d).padStart(2,'0')}</div>
          <div class="sc-wk-name">${r.wk.substring(0,3).toUpperCase()}</div>
        </div>
        <div class="sc-wk-div"></div>
        <div class="sc-wk-evs">
          ${r.items.map(ev=>`<div class="sc-wk-ev" style="color:${ev.color}">${ev.name}${ev.time?' · '+ev.time:''}</div>`).join('')}
        </div>
      </div>`).join('')
    :`<div class="sc-noev">Nenhum evento especial esta semana</div>`;
  buildSC(`<div class="sc"><div class="sc-bg"></div><div class="sc-inner">
    ${scTop('Semana')}
    <div class="sc-month" style="font-size:40px">${fmt(ws)}</div>
    <div class="sc-month-sub">${fmt(we)} · Programação</div>
    ${rowsHtml}
    ${scFooter()}
  </div></div>`);
  openShareModal();
}

function openShareAnn(i){
  const a=anns[i];
  const c=TCOLORS[a.type]||'#00E896';
  const tlab={green:'Aviso',gold:'Evento Especial',coral:'Urgente',sky:'Informação'}[a.type]||'Aviso';
  buildSC(`<div class="sc"><div class="sc-bg"></div><div class="sc-inner">
    ${scTop('Aviso')}
    <div style="margin-top:8px">
      <div class="sc-ann-type" style="background:${c}18;color:${c};border:1px solid ${c}40">
        <span style="width:6px;height:6px;border-radius:50%;background:${c};display:inline-block"></span>${tlab}
      </div>
      <div class="sc-ann-title">${a.title}</div>
      <div class="sc-ann-text">${a.text}</div>
    </div>
    ${scFooter(a.date)}
  </div></div>`);
  openShareModal();
}

function buildSC(html){document.getElementById('share-card').innerHTML=html;}

function openShareModal(){
  document.getElementById('prev-load').style.display='block';
  document.getElementById('preview-img').style.display='none';
  document.getElementById('smoverlay').classList.add('open');
  setTimeout(()=>{
    const sc=document.getElementById('share-card');
    html2canvas(sc,{scale:2,backgroundColor:'#071A10',useCORS:true,logging:false,width:540,windowWidth:540})
      .then(canvas=>{
        shareDataURL=canvas.toDataURL('image/png');
        document.getElementById('prev-load').style.display='none';
        const img=document.getElementById('preview-img');
        img.src=shareDataURL;img.style.display='block';
      });
  },120);
}
function closeShare(){document.getElementById('smoverlay').classList.remove('open');}
function dlImg(){
  if(!shareDataURL)return;
  const a=document.createElement('a');
  a.href=shareDataURL;
  a.download=`ieadern-${Date.now()}.png`;
  a.click();
}

document.getElementById('moverlay').addEventListener('click',function(e){if(e.target===this)closeMod();});
document.getElementById('smoverlay').addEventListener('click',function(e){if(e.target===this)closeShare();});

render();
